data.configuration#Configuration:
Create a tsproxy.config.ts in your project root:
import { defineConfig } from "@tsproxy/api";
export default defineConfig({
  typesense: {
    host: "localhost",
    port: 8108,
    protocol: "http",
    apiKey: "your-api-key",
  },
  server: {
    port: 3000,
    apiKey: "your-ingest-secret",
  },
  cache: { ttl: 60, maxSize: 1000 },
  queue: {
    concurrency: 5,
    maxSize: 10000,
    redis: { host: "localhost", port: 6379 },
  },
  rateLimit: { search: 100, ingest: 30 },
  collections: {
    products: {
      fields: {
        name: { type: "string", searchable: true },
        description: { type: "string", searchable: true, optional: true },
        price: { type: "float", sortable: true },
        category: { type: "string", facet: true },
        brand: { type: "string", facet: true },
      },
    },
  },
});

data.how-it-works#How It Works:
When you define locales in your config, tsproxy automatically maps collection names to locale-specific variants:
// tsproxy.config.ts
collections: {
  products: {
    fields: { /* ... */ },
    locales: ["en", "fr", "de"],
  },
}
This creates the mapping:
products + locale en → products_en
products + locale fr → products_fr
products + locale de → products_de

data.using-with-tsproxyjs#Using with @tsproxy:
const client = createSearchClient({
  url: "http://localhost:3000",
  locale: "fr",
});
The adapter automatically sends the X-Locale header with every request.

data.computed-fields-with-locale#Computed Fie:
Computed fields receive the locale, enabling locale-aware transformations:
category_page_slug: {
  type: "string",
  facet: true,
  compute: (doc, locale) => {
    const color = String(doc.color || "").toLowerCase();
    const category = String(doc.category || "").toLowerCase();
    // Could use locale for translations
    return `${color}-${category}`.replace(/\s+/g, "-");
  },
}

data.basic-setup#Basic Setup:
import { useMemo } from "react";
import { InstantSearch, Configure } from "react-instantsearch";
import { createSearchClient } from "@tsproxy/js";
import { SearchBox, Hits, RefinementList, Pagination, Stats } from "@tsproxy/react";
export default function SearchPage() {
  const searchClient = useMemo(
    () => createSearchClient({ url: "http://localhost:3000" }),
    [],
  );
  return (
    <InstantSearch searchClient={searchClient} indexName="products">
      <Configure hitsPerPage={12} />
      <SearchBox placeholder="Search..." />
      <Stats />
      <RefinementList attribute="category" />
      <Hits hitComponent={({ hit }) => <div>{hit.name}</div>} />
      <Pagination />
    </InstantSearch>
  );
}

data.overrides-pattern#Overrides Pattern:
Every @tsproxy/react component accepts an overrides prop to customize or replace any sub-element:
<SearchBox
  overrides={{
    Input: {
      props: { className: "rounded-full border px-4 py-2" },
    },
    SubmitButton: { props: { hidden: true } },
    ResetButton: {
      component: ({ onClick, hidden }) => (
        <button onClick={onClick} hidden={hidden}>Clear</button>
      ),
    },
  }}
/>
Each override accepts:
props — merge additional props (object or function (defaultProps) => overrideProps)
component — replace the sub-element entirely with a custom component

data.debounced-search#Debounced Search:
Use queryHook to debounce search requests:
import { useRef, useCallback } from "react";
function useDebouncedSearch(delay = 300) {
  const timerRef = useRef(undefined);
  return useCallback(
    (query, search) => {
      clearTimeout(timerRef.current);
      timerRef.current = setTimeout(() => search(query), delay);
    },
    [delay],
  );
}
// In your component:
const debouncedSearch = useDebouncedSearch(300);
<SearchBox queryHook={debouncedSearch} />

